  "questionProse": [
    "क्या आप एक <em class=\"highlight\">सही</em> 👍 हेक्स कोड ढूंढ सकते हैं?"
  ],
  "explanationProse": [
    "हेक्स कोड का उपयोग CSS में रंगों को दर्शाने के लिए किया जा सकता है। वे `#` से शुरू होते हैं और इनमें 3, 4, 6 या 8 हेक्साडेसिमल अंक होने चाहिए।\n      \n      3-अक्षर वाला हेक्स कोड 6-अक्षर वाले कोड का शॉर्टहैंड है, जहाँ प्रत्येक अक्षर दोहराया जाता है। 4-अक्षर वाले कोड में पारदर्शिता के लिए अल्फा चैनल शामिल होता है।\n\n      उदाहरण के लिए `#ABC` `#AABBCC` के समान है, और `#ABCD` `#AABBCCDD` के समान है। हेक्स मानों को संभालने के बारे में अधिक जानने के लिए, मेरी [JavaScript संख्याओं की प्रश्नोत्तरी](/quiz-can-you-count-to-bigint/) देखें।"
  ]
}
